-- ─── Trigger helper: keep updated_at fresh ──────────────────────────────────
CREATE OR REPLACE FUNCTION public.touch_updated_at()
RETURNS TRIGGER
LANGUAGE plpgsql
AS $$
BEGIN
  NEW.updated_at = NOW();
  RETURN NEW;
END;
$$;

-- Apply to tables that have an updated_at column
DO $$
DECLARE
  t TEXT;
BEGIN
  FOR t IN
    SELECT unnest(ARRAY[
      'tenants', 'subscriptions', 'channex_properties', 'properties',
      'bookings', 'message_templates',
      'teammates', 'cleaning_checklists', 'cleaning_rules'
    ])
  LOOP
    EXECUTE format(
      'DROP TRIGGER IF EXISTS touch_%I ON public.%I; ' ||
      'CREATE TRIGGER touch_%I BEFORE UPDATE ON public.%I ' ||
      'FOR EACH ROW EXECUTE FUNCTION public.touch_updated_at();',
      t, t, t, t
    );
  END LOOP;
END;
$$;
